package org.example.academia.ui;

import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.stage.Stage;

public class MainApp extends Application {

    @Override
    public void start(Stage primaryStage) throws Exception {
        // En una versión posterior se cargará login.fxml desde resources
        Parent root = new FXMLLoader(getClass().getResource("/ui/view/login.fxml")).load();
        primaryStage.setTitle("Academia de Belleza");
        primaryStage.setScene(new Scene(root));
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

package org.example.academia.ui.controller;

import javafx.fxml.FXML;
import javafx.scene.control.Label;
import javafx.scene.control.PasswordField;
import javafx.scene.control.TextField;

public class LoginController {

    @FXML
    private TextField usernameField;

    @FXML
    private PasswordField passwordField;

    @FXML
    private Label messageLabel;

    @FXML
    private void onLogin() {
        String username = usernameField.getText();
        String password = passwordField.getText();

        // Lógica temporal hasta implementar SeguridadService
        if ("admin".equals(username) && "admin".equals(password)) {
            messageLabel.setText("Login correcto (mock)");
        } else {
            messageLabel.setText("Usuario o contraseña incorrectos");
        }
    }
}

